-- TPC-DS schema with UPPERCASE quoted identifiers (matching Substrait plans).
-- Data loaded from pipe-delimited .dat files generated by dsdgen.
-- Generated queries reference "tpcds"."TABLE" so we create a tpcds schema.

DROP SCHEMA IF EXISTS "tpcds" CASCADE;
CREATE SCHEMA "tpcds";

CREATE TABLE "tpcds"."CALL_CENTER" (
  "CC_CALL_CENTER_SK" BIGINT,
  "CC_CALL_CENTER_ID" CHAR(16),
  "CC_REC_START_DATE" DATE,
  "CC_REC_END_DATE" DATE,
  "CC_CLOSED_DATE_SK" INTEGER,
  "CC_OPEN_DATE_SK" INTEGER,
  "CC_NAME" VARCHAR(50),
  "CC_CLASS" VARCHAR(50),
  "CC_EMPLOYEES" INTEGER,
  "CC_SQ_FT" INTEGER,
  "CC_HOURS" CHAR(20),
  "CC_MANAGER" VARCHAR(40),
  "CC_MKT_ID" INTEGER,
  "CC_MKT_CLASS" CHAR(50),
  "CC_MKT_DESC" VARCHAR(100),
  "CC_MARKET_MANAGER" VARCHAR(40),
  "CC_DIVISION" INTEGER,
  "CC_DIVISION_NAME" VARCHAR(50),
  "CC_COMPANY" INTEGER,
  "CC_COMPANY_NAME" CHAR(50),
  "CC_STREET_NUMBER" CHAR(10),
  "CC_STREET_NAME" VARCHAR(60),
  "CC_STREET_TYPE" CHAR(15),
  "CC_SUITE_NUMBER" CHAR(10),
  "CC_CITY" VARCHAR(60),
  "CC_COUNTY" VARCHAR(30),
  "CC_STATE" CHAR(2),
  "CC_ZIP" CHAR(10),
  "CC_COUNTRY" VARCHAR(20),
  "CC_GMT_OFFSET" DECIMAL(5,2),
  "CC_TAX_PERCENTAGE" DECIMAL(5,2));

